|other_names = '''Toyama Utaki''' (十山御嶽, ''Toyama Ugan'')
|festival = {{ill|June 26 (lunar calendar)|ja|6月26日 (旧暦)|qq=draft|qq=draft}}
|map = Japan Okinawa
